namespace Warehouse;

/// <summary>
/// Tracks per-warehouse stock levels, raises reorder alerts, and supports
/// transferring inventory between warehouses.
/// </summary>
public sealed class InventoryTracker
{
    private readonly int _reorderThreshold;

    // warehouseId -> (sku -> quantity)
    private readonly Dictionary<string, Dictionary<string, int>> _stock = new(StringComparer.OrdinalIgnoreCase);

    public const string DefaultWarehouse = "MAIN";

    public InventoryTracker(int reorderThreshold = 10)
    {
        if (reorderThreshold < 0)
            throw new ArgumentOutOfRangeException(nameof(reorderThreshold), "Reorder threshold cannot be negative.");

        _reorderThreshold = reorderThreshold;
    }

    public int ReorderThreshold => _reorderThreshold;

    // ── Stock queries ────────────────────────────────────────────────

    public int GetStockLevel(string sku) =>
        GetStockLevel(sku, DefaultWarehouse);

    public int GetStockLevel(string sku, string warehouseId)
    {
        ValidateSku(sku);
        ValidateWarehouseId(warehouseId);

        if (_stock.TryGetValue(warehouseId, out var warehouse) &&
            warehouse.TryGetValue(sku, out var qty))
        {
            return qty;
        }

        return 0;
    }

    public int GetTotalStockLevel(string sku)
    {
        ValidateSku(sku);

        int total = 0;
        foreach (var warehouse in _stock.Values)
        {
            if (warehouse.TryGetValue(sku, out var qty))
                total += qty;
        }
        return total;
    }

    // ── Stock mutations ──────────────────────────────────────────────

    public void AddStock(string sku, int quantity) =>
        AddStock(sku, quantity, DefaultWarehouse);

    public void AddStock(string sku, int quantity, string warehouseId)
    {
        ValidateSku(sku);
        ValidateWarehouseId(warehouseId);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");

        var warehouse = GetOrCreateWarehouse(warehouseId);

        warehouse.TryGetValue(sku, out var current);
        warehouse[sku] = current + quantity;
    }

    public void RemoveStock(string sku, int quantity) =>
        RemoveStock(sku, quantity, DefaultWarehouse);

    public void RemoveStock(string sku, int quantity, string warehouseId)
    {
        ValidateSku(sku);
        ValidateWarehouseId(warehouseId);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");

        if (!_stock.TryGetValue(warehouseId, out var warehouse) ||
            !warehouse.TryGetValue(sku, out var current) ||
            current < quantity)
        {
            throw new InvalidOperationException(
                $"Insufficient stock for SKU '{sku}' in warehouse '{warehouseId}'. " +
                $"Requested: {quantity}, Available: {GetStockLevel(sku, warehouseId)}.");
        }

        warehouse[sku] = current - quantity;
    }

    // ── Reorder alerts ───────────────────────────────────────────────

    public bool NeedsReorder(string sku) =>
        NeedsReorder(sku, DefaultWarehouse);

    public bool NeedsReorder(string sku, string warehouseId)
    {
        ValidateSku(sku);
        ValidateWarehouseId(warehouseId);
        return GetStockLevel(sku, warehouseId) < _reorderThreshold;
    }

    public IReadOnlyList<string> GetSkusNeedingReorder(string warehouseId)
    {
        ValidateWarehouseId(warehouseId);

        if (!_stock.TryGetValue(warehouseId, out var warehouse))
            return Array.Empty<string>();

        return warehouse
            .Where(kvp => kvp.Value < _reorderThreshold)
            .Select(kvp => kvp.Key)
            .OrderBy(s => s, StringComparer.OrdinalIgnoreCase)
            .ToList()
            .AsReadOnly();
    }

    // ── Warehouse transfers ──────────────────────────────────────────

    public void TransferStock(string sku, int quantity, string fromWarehouse, string toWarehouse)
    {
        ValidateSku(sku);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");
        ValidateWarehouseId(fromWarehouse);
        ValidateWarehouseId(toWarehouse);

        if (string.Equals(fromWarehouse, toWarehouse, StringComparison.OrdinalIgnoreCase))
            throw new ArgumentException("Source and destination warehouses must be different.");

        RemoveStock(sku, quantity, fromWarehouse);
        AddStock(sku, quantity, toWarehouse);
    }

    // ── Helpers ──────────────────────────────────────────────────────

    private Dictionary<string, int> GetOrCreateWarehouse(string warehouseId)
    {
        if (!_stock.TryGetValue(warehouseId, out var warehouse))
        {
            warehouse = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            _stock[warehouseId] = warehouse;
        }
        return warehouse;
    }

    private static void ValidateSku(string sku)
    {
        if (string.IsNullOrWhiteSpace(sku))
            throw new ArgumentException("SKU cannot be null or empty.", nameof(sku));
    }

    private static void ValidateWarehouseId(string warehouseId)
    {
        if (string.IsNullOrWhiteSpace(warehouseId))
            throw new ArgumentException("Warehouse ID cannot be null or empty.", nameof(warehouseId));
    }
}

